from __future__ import annotations


def management_report_dashboard_html() -> str:
    return r'''<!doctype html><html lang="ru"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Сводка руководителя</title><style>
:root{color-scheme:dark;--bg:#07101d;--panel:#101b2d;--panel2:#142238;--line:#283956;--text:#eef5ff;--muted:#91a3bd;--accent:#6d8cff;--ok:#35d08a;--warn:#ffbd4a;--bad:#ff5d78}*{box-sizing:border-box}body{margin:0;background:radial-gradient(circle at 80% 0,rgba(109,140,255,.14),transparent 30%),var(--bg);color:var(--text);font:14px/1.5 Inter,Segoe UI,Arial,sans-serif}main{max-width:1380px;margin:auto;padding:24px 28px 80px}.hero{display:flex;justify-content:space-between;gap:20px;align-items:flex-start;margin-bottom:18px}.hero h1{margin:0;font-size:28px}.hero p{color:var(--muted);max-width:800px;margin:7px 0}.actions{display:flex;gap:8px;flex-wrap:wrap}button,a.btn{border:1px solid var(--line);background:var(--panel);color:var(--text);padding:9px 12px;border-radius:10px;cursor:pointer;text-decoration:none}.primary{background:linear-gradient(135deg,#496ee8,#7657de);border:0}.status{color:var(--muted);font-size:12px}.summary{display:grid;grid-template-columns:1.35fr repeat(3,1fr);gap:12px;margin-bottom:14px}.card{background:linear-gradient(180deg,rgba(20,34,56,.97),rgba(12,23,39,.97));border:1px solid var(--line);border-radius:15px;padding:18px}.hero-card{display:flex;gap:18px;align-items:center}.score{font-size:52px;font-weight:800;line-height:1}.grade{font-size:16px;color:var(--muted)}.metric .label{color:var(--muted);font-size:12px}.metric .value{font-size:28px;font-weight:750;margin:6px 0}.metric .note{font-size:12px;color:var(--muted)}.bad{color:var(--bad)}.warn{color:var(--warn)}.ok{color:var(--ok)}.layout{display:grid;grid-template-columns:1.25fr .75fr;gap:14px}.section{background:rgba(16,27,45,.82);border:1px solid var(--line);border-radius:15px;padding:18px;margin-bottom:14px}.section h2{margin:0 0 13px;font-size:17px}.issue{display:grid;grid-template-columns:36px 1fr;gap:11px;padding:13px 0;border-bottom:1px solid rgba(40,57,86,.75)}.issue:last-child{border-bottom:0}.rank{width:30px;height:30px;border-radius:9px;display:grid;place-items:center;background:rgba(255,93,120,.14);color:var(--bad);font-weight:800}.issue h3{margin:0 0 3px;font-size:14px}.issue p{margin:3px 0;color:var(--muted)}.decision{padding:12px;border-radius:11px;background:rgba(109,140,255,.09);border:1px solid rgba(109,140,255,.28);margin:9px 0}.decision b{display:block;margin-bottom:4px}.roi{display:grid;grid-template-columns:1fr 1fr;gap:10px}.roi .box{padding:14px;border-radius:12px;background:rgba(53,208,138,.08);border:1px solid rgba(53,208,138,.25)}.roi strong{font-size:24px;color:var(--ok)}.departments .row,.dimensions .row{display:grid;grid-template-columns:1fr auto;gap:10px;padding:9px 0;border-bottom:1px solid rgba(40,57,86,.65)}.bar{height:6px;background:#1b2b44;border-radius:99px;overflow:hidden;margin-top:6px}.bar i{display:block;height:100%;background:linear-gradient(90deg,#ff5d78,#ffbd4a,#35d08a)}details{background:rgba(16,27,45,.72);border:1px solid var(--line);border-radius:14px;padding:14px;margin-top:14px}summary{cursor:pointer;font-weight:700}.history{margin-top:14px}.history table{width:100%;border-collapse:collapse}.history th,.history td{padding:10px;border-bottom:1px solid var(--line);text-align:left}.empty{color:var(--muted);padding:18px}.loading{animation:pulse 1.1s infinite alternate}@keyframes pulse{to{opacity:.45}}@media(max-width:1050px){.summary{grid-template-columns:1fr 1fr}.layout{grid-template-columns:1fr}}@media(max-width:650px){main{padding:18px}.hero{display:block}.summary{grid-template-columns:1fr}.roi{grid-template-columns:1fr}}
</style></head><body><main><div class="hero"><div><h1>Сводка руководителя</h1><p>Что происходит, что требует решения и какой результат даст исправление. Данные обновляются автоматически при открытии страницы.</p><div class="status" id="updated">Загрузка актуальных данных…</div></div><div class="actions"><button id="refresh">Обновить данные</button><a class="btn" href="/executive-intelligence" target="_blank">Открыть аналитику</a></div></div>
<div id="content" class="loading"><div class="section empty">Формируется управленческая сводка…</div></div>
<details><summary>Подробный отчёт и история</summary><div class="actions" style="margin:14px 0"><button id="generate">Сформировать подробный PDF</button><a class="btn" id="latestPdf">Последний PDF</a></div><div class="history"><table><thead><tr><th>Дата</th><th>Режим</th><th>Действие</th></tr></thead><tbody id="history"></tbody></table></div><div class="status" id="reportStatus"></div></details>
</main><script>
const $=s=>document.querySelector(s);function esc(v){const d=document.createElement('div');d.textContent=v??'';return d.innerHTML}function money(v){return v==null?'не рассчитано':new Intl.NumberFormat('ru-RU').format(Math.round(v))+' ₸'}function num(v){return new Intl.NumberFormat('ru-RU',{maximumFractionDigits:1}).format(Number(v||0))}function severity(v){return v==='critical'?'Критично':v==='high'?'Высокий риск':v==='medium'?'Требует внимания':'Наблюдение'}
function decisions(d){const out=[];const risks=d.risks||[];if(risks.some(x=>String(x.title).toLowerCase().includes('срок')))out.push(['Утвердить обязательные сроки задач','Запретить рабочие задачи без крайнего срока и включить автоматическую эскалацию.']);if(risks.some(x=>String(x.title).includes('CRM')))out.push(['Утвердить единые правила ведения CRM','Закрепить обязательные поля, следующее действие и контроль сделок без активности.']);if(risks.some(x=>String(x.title).toLowerCase().includes('документооборот')))out.push(['Назначить владельца документооборота','Утвердить единые маршруты, сроки согласования и ответственность.']);if(risks.some(x=>String(x.title).toLowerCase().includes('автоматизац')))out.push(['Утвердить план автоматизации','Начать с процессов с максимальной экономией времени.']);return out.slice(0,3)}
function render(d){const maturity=d.digital_maturity||{},src=d.source_summary||{},roi=d.roi||{},risks=(d.risks||[]).slice(0,5),deps=(d.department_rating||[]).slice(0,5),dims=Object.values(d.dimensions||{}),dec=decisions(d);let html='<div class="summary"><div class="card hero-card"><div><div class="score">'+esc(num(maturity.score))+'</div><div class="grade">из 100 · '+esc(maturity.level||'нет оценки')+' · '+esc(maturity.grade||'')+'</div></div><div><b>Состояние компании</b><p class="'+(Number(maturity.score)<55?'bad':Number(maturity.score)<70?'warn':'ok')+'">'+(Number(maturity.score)<55?'Требует срочного внимания':Number(maturity.score)<70?'Есть существенные слабые места':'В целом управляемо')+'</p></div></div><div class="card metric"><div class="label">Просрочка</div><div class="value bad">'+esc(num(src.overdue_rate))+'%</div><div class="note">доля открытых задач</div></div><div class="card metric"><div class="label">Без срока</div><div class="value warn">'+esc(src.without_deadline||0)+'</div><div class="note">задач невозможно контролировать по срокам</div></div><div class="card metric"><div class="label">Сотрудники в риске</div><div class="value bad">'+esc(src.employees_at_risk||0)+'</div><div class="note">нужна проверка нагрузки</div></div></div>';
html+='<div class="layout"><div><section class="section"><h2>Что требует внимания сейчас</h2>'+(risks.length?risks.map((r,i)=>'<div class="issue"><div class="rank">'+(i+1)+'</div><div><h3>'+esc(r.title)+'</h3><p><b>'+esc(severity(r.severity))+':</b> '+esc(r.fact||'')+'</p><p>Последствие: '+esc(r.impact||'')+'</p></div></div>').join(''):'<div class="empty">Критичных рисков не выявлено.</div>')+'</section><section class="section"><h2>Что необходимо решить руководству</h2>'+(dec.length?dec.map(x=>'<div class="decision"><b>'+esc(x[0])+'</b><span>'+esc(x[1])+'</span></div>').join(''):'<div class="empty">Отдельных решений руководства сейчас не требуется.</div>')+'</section></div><div><section class="section"><h2>Ожидаемый эффект</h2><div class="roi"><div class="box"><span>Экономия времени</span><br><strong>'+esc(num(roi.total_annual_hours))+'</strong><br><small>часов в год</small></div><div class="box"><span>Экономический эффект</span><br><strong>'+esc(money(roi.total_annual_saving_kzt))+'</strong><br><small>ориентир в год</small></div></div></section><section class="section departments"><h2>Подразделения, требующие внимания</h2>'+(deps.length?deps.map(x=>'<div class="row"><div>'+esc(x.name)+'<div class="bar"><i style="width:'+Math.max(0,Math.min(100,x.score||0))+'%"></i></div></div><b class="'+(x.score<55?'bad':x.score<70?'warn':'ok')+'">'+esc(num(x.score))+'</b></div>').join(''):'<div class="empty">Недостаточно данных по подразделениям.</div>')+'</section><section class="section dimensions"><h2>Ключевые направления</h2>'+dims.map(x=>'<div class="row"><span>'+esc(x.title)+'</span><b class="'+(x.score<55?'bad':x.score<70?'warn':'ok')+'">'+esc(num(x.score))+'</b></div>').join('')+'</section></div></div>';$('#content').innerHTML=html;$('#content').classList.remove('loading');$('#updated').textContent='Данные обновлены: '+new Date(d.generated_at).toLocaleString('ru-RU')}
async function refresh(){try{$('#content').classList.add('loading');const r=await fetch('/executive-intelligence/collect',{method:'POST'});const d=await r.json();if(!r.ok)throw new Error(d.detail||'Ошибка обновления');render(d)}catch(e){$('#content').innerHTML='<div class="section bad">Не удалось обновить сводку: '+esc(e.message)+'</div>';$('#content').classList.remove('loading')}}
async function history(){try{const r=await fetch('/management-reports');const rows=await r.json();$('#history').innerHTML=rows.length?rows.map((x,i)=>'<tr><td>'+esc(new Date(x.generated_at).toLocaleString('ru-RU'))+'</td><td>'+(x.mode==='detailed'?'Подробный':'Краткий')+'</td><td><a class="btn" href="/management-reports/'+x.id+'/pdf">PDF</a></td></tr>').join(''):'<tr><td colspan="3" class="empty">Подробных отчётов пока нет.</td></tr>';if(rows[0])$('#latestPdf').href='/management-reports/'+rows[0].id+'/pdf'}catch(e){$('#history').innerHTML='<tr><td colspan="3">Ошибка загрузки истории.</td></tr>'}}
$('#refresh').onclick=refresh;$('#generate').onclick=async()=>{try{$('#generate').disabled=true;$('#reportStatus').textContent='Формируется подробный отчёт…';const r=await fetch('/management-reports/generate?mode=detailed',{method:'POST'});const d=await r.json();if(!r.ok)throw new Error(d.detail||'Ошибка генерации');$('#reportStatus').textContent='Подробный отчёт готов.';await history();window.open('/management-reports/'+d.id+'/pdf','_blank')}catch(e){$('#reportStatus').textContent='Ошибка: '+e.message}finally{$('#generate').disabled=false}};refresh();history();setInterval(refresh,300000);
</script></body></html>'''
